import React, { Component } from 'react';
import { styled, createTheme, ThemeProvider } from '@mui/material/styles';
import {
  CssBaseline,
  Box,
  AppBar as MuiAppBar,
  Toolbar,
  Link,
  Container,
  Typography,
  Grid,
  Card,
  CardContent,
  Button,
  TextField
} from '@mui/material';

const AppBar = styled(MuiAppBar)(({ theme }) => ({
  zIndex: theme.zIndex.drawer + 1,
}));

const defaultTheme = createTheme();

export default class Dashboard extends Component {
  constructor(props) {
    super(props);
    this.state = {
      isNightMode: false,
      name: '',
      email: '',
      message: '',
    };
  }

  toggleTheme = () => {
    this.setState((prevState) => ({
      isNightMode: !prevState.isNightMode,
    }));
  };

  handleChange = (e) => {
    this.setState({ [e.target.name]: e.target.value });
  };

  handleSubmit = (e) => {
    e.preventDefault();
    // Handle form submission logic here
    console.log('Form submitted:', this.state);
  };

  render() {
    const { isNightMode, name, email, message } = this.state;

    const projects = [
      {
        title: 'Project 1',
        description: 'A full-stack e-commerce platform built with React, Node.js, and MongoDB. Users can browse, add products to the cart, and checkout.',
        link: 'https://github.com/yourusername/project1',
      },
      {
        title: 'Project 2',
        description: 'A responsive personal blog built using React and styled-components, focusing on clean UI and performance optimization.',
        link: 'https://github.com/yourusername/project2',
      },
      // Add more projects as needed
    ];

    return (
      <ThemeProvider theme={defaultTheme}>
        <CssBaseline />
        <Box
          sx={{
            display: 'flex',
            flexDirection: 'column',
            height: '100vh',
            backgroundColor: isNightMode ? '#333' : '#fff',
            color: isNightMode ? '#fff' : '#000',
            padding: 2,
          }}
        >
          <AppBar position="absolute">
            <Toolbar component="nav" variant="dense" sx={{ justifyContent: 'space-between', overflowX: 'auto' }}>
              <Typography variant="h6" sx={{ fontWeight: 'bold' }}>My Portfolio</Typography>
              {[
                { title: "About", url: "#about" },
                { title: "Skills", url: "#skills" },
                { title: "Experience", url: "#experience" },
                { title: "Projects", url: "#projects" },
                { title: "Education", url: "#education" },
                { title: "Contact", url: "#contact" }
              ].map((section) => (
                <Link
                  color="inherit"
                  noWrap
                  key={section.title}
                  variant="body2"
                  href={section.url}
                  sx={{
                    p: 1,
                    flexShrink: 0,
                    fontWeight: 600,
                    transition: 'color 0.3s',
                    '&:hover': {
                      color: isNightMode ? '#ddd' : '#1976d2',
                    }
                  }}
                >
                  {section.title}
                </Link>
              ))}
              <Button onClick={this.toggleTheme} variant="contained" color="primary">
                {isNightMode ? 'Switch to Day Mode' : 'Switch to Night Mode'}
              </Button>
            </Toolbar>
          </AppBar>

          <Box component="main" sx={{ flexGrow: 1, overflow: 'auto', padding: 2 }}>
            <Container id="home" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
              <Typography variant="h2" gutterBottom sx={{ fontWeight: 'bold' }}>
                Welcome to My Portfolio
              </Typography>
              <Typography variant="h5">
                I am a passionate web developer specializing in React.js and React Native.
              </Typography>
            </Container>

            <Container id="about" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
              <Typography variant="h4" gutterBottom sx={{ fontWeight: 'bold' }}>
                About Me
              </Typography>
              <Typography variant="body1">
                I am a Senior Software Developer with over 6 years of experience in web development. I have a strong
                background in full-stack development and specialize in JavaScript, React, React Native, and cloud technologies.
              </Typography>
            </Container>

            <Container id="projects" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
              <Typography variant="h4" gutterBottom sx={{ fontWeight: 'bold' }}>
                Projects
              </Typography>
              <Grid container spacing={2}>
                {projects.map((project, index) => (
                  <Grid item xs={12} sm={6} md={4} key={index}>
                    <Card sx={{ boxShadow: 3, borderRadius: 2 }}>
                      <CardContent>
                        <Typography variant="h5" sx={{ fontWeight: 'bold' }}>{project.title}</Typography>
                        <Typography variant="body2" sx={{ mb: 2 }}>{project.description}</Typography>
                        <Button href={project.link} target="_blank" variant="contained" color="primary">
                          View Project
                        </Button>
                      </CardContent>
                    </Card>
                  </Grid>
                ))}
              </Grid>
            </Container>

            <Container id="skills" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
              <Typography variant="h4" gutterBottom sx={{ fontWeight: 'bold' }}>
                Skills
              </Typography>
              <Typography variant="body1">
                JavaScript, React.js, React Native, Node.js, Express.js, HTML, CSS, TypeScript, AWS, Azure, MongoDB, MySQL, PostgreSQL, Git, REST APIs, GraphQL, etc.
              </Typography>
            </Container>

            <Container id="experience" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
              <Typography variant="h4" gutterBottom sx={{ fontWeight: 'bold' }}>
                Experience
              </Typography>
              <Typography variant="body1">
                Senior Software Developer at WovvTech - Leading a team, providing training, and building scalable web and mobile applications.
              </Typography>
              <Typography variant="body1" sx={{ mt: 2 }}>
                Previous work experiences include full-stack development, building e-commerce platforms, and implementing cloud-based solutions for startups.
              </Typography>
            </Container>

            <Container id="education" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
              <Typography variant="h4" gutterBottom sx={{ fontWeight: 'bold' }}>
                Education
              </Typography>
              <Typography variant="body1">
                MCA (Master of Computer Applications) - Gangadhar Meher University, 2018
              </Typography>
            </Container>

            <Container id="contact" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
              <Typography variant="h4" gutterBottom sx={{ fontWeight: 'bold' }}>
                Contact Me
              </Typography>
              <form onSubmit={this.handleSubmit}>
                <TextField
                  label="Name"
                  name="name"
                  value={name}
                  onChange={this.handleChange}
                  fullWidth
                  required
                  sx={{ mb: 2 }}
                />
                <TextField
                  label="Email"
                  name="email"
                  type="email"
                  value={email}
                  onChange={this.handleChange}
                  fullWidth
                  required
                  sx={{ mb: 2 }}
                />
                <TextField
                  label="Message"
                  name="message"
                  value={message}
                  onChange={this.handleChange}
                  multiline
                  rows={4}
                  fullWidth
                  required
                  sx={{ mb: 2 }}
                />
                <Button type="submit" variant="contained" color="primary">
                  Send Message
                </Button>
              </form>
            </Container>
          </Box>
        </Box>
      </ThemeProvider>
    );
  }
}
